<?php if (!defined('ABSPATH')) exit; get_header(); $s = get_search_query(); ?>
<div class="flavor-container py-8"><h1 class="text-4xl font-bold mb-6">Búsqueda de viajes: "<?php echo esc_html($s); ?>"</h1><form method="get" class="mb-8 flex gap-2"><input type="text" name="s" value="<?php echo esc_attr($s); ?>" class="flex-1 px-4 py-3 border rounded-lg" autofocus/><button type="submit" class="px-6 py-3 bg-primary text-white rounded-lg">Buscar</button></form><?php $q = new WP_Query(array('post_type' => 'carpooling', 's' => $s)); if ($q->have_posts()) : echo '<div class="space-y-6">'; while ($q->have_posts()) : $q->the_post(); $origen = get_post_meta(get_the_ID(), '_origen', true); $destino = get_post_meta(get_the_ID(), '_destino', true); $fecha = get_post_meta(get_the_ID(), '_fecha_viaje', true); $precio = get_post_meta(get_the_ID(), '_precio_plaza', true); echo '<article class="bg-white rounded-xl shadow-md p-6"><h2 class="text-2xl font-bold mb-2"><a href="' . get_permalink() . '" class="hover:text-primary">' . esc_html($origen) . ' → ' . esc_html($destino) . '</a></h2><p class="text-gray-600 mb-3">' . date_i18n('d/m/Y', strtotime($fecha)) . '</p><p class="text-2xl font-bold text-primary">' . esc_html($precio) . '€</p><a href="' . get_permalink() . '" class="mt-4 inline-block px-6 py-2 bg-primary text-white rounded-lg">Ver Viaje</a></article>'; endwhile; echo '</div>'; else : echo '<div class="text-center py-16"><h3 class="text-2xl font-bold">No se encontraron viajes</h3></div>'; endif; wp_reset_postdata(); ?></div><?php get_footer(); ?>
